fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size

    // 1. Calculate closest(x) for all x
    val closest = IntArray(n) { -1 }
    for (x in 0 until n) {
        var minDiff = Long.MAX_VALUE
        var bestY = -1

