        val candidates = mutableListOf<Int>()
        if (x > 0) candidates.add(x - 1)
        if (x < n - 1) candidates.add(x + 1)

        for (y in candidates) {
            val diff = abs(nums[x] - nums[y])

            if (diff < minDiff) {
                minDiff = diff
                bestY = y
            } else if (diff == minDiff) {
                // If differences are equal, choose the smaller index
                if (bestY == -1 || y < bestY) {
                    bestY = y
                }
