import java.util.PriorityQueue

fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size

    // 1. Calculate closest(x) for all x
    val closest = IntArray(n)
    for (x in 0 until n) {
        var minDiff = Long.MAX_VALUE
        var bestY = -1

        // Check adjacent indices y = x-1 and y = x+1
        val candidates = mutableListOf<Int>()
        if (x > 0) candidates.add(x - 1)
        if (x < n - 1) candidates.add(x + 1)

        for (y in candidates) {
            val diff = Math.abs(nums[x] - nums[y])

            if (diff < minDiff) {
                minDiff = diff
                bestY = y
            } else if (diff == minDiff) {
                // If differences are equal, choose the smaller index
                if (y < bestY || bestY == -1) {
                    bestY = y
                }
            }
        }
        closest[x] = bestY
    }

    val results = mutableListOf<Long>()

    for (query in queries) {
        val L = query[0].toInt()
        val R = query[1].toInt()

        if (L == R) {
            results.add(0L)
            continue
        }

        // Dijkstra's Algorithm
        val dist = LongArray(n) { Long.MAX_VALUE }
        dist[L] = 0L

        // Priority Queue: [distance, index]
        // We use Pair<Long, Int> for (cost, index)
        val pq = PriorityQueue<Pair<Long, Int>>(compareBy { it.first })
        pq.add(Pair(0L, L))

        var targetReached = false

        while (pq.isNotEmpty()) {
            val (d_u, u) = pq.poll()

            if (d_u > dist[u]) {
                continue
            }

            if (u == R) {
                results.add(d_u)
                targetReached = true
                break
            }

            // 1. Type 2 Move: Move to closest(u)
            val v_close = closest[u]
            val cost_2 = 1L
            val new_dist_2 = dist[u] + cost_2

            if (new_dist_2 < dist[v_close]) {
                dist[v_close] = new_dist_2
                pq.add(Pair(new_dist_2, v_close))
            }

            // 2. Type 1 Move: Jump to any v
            // This is the potentially slow O(N) relaxation step per node extraction.
            for (v in 0 until n) {
                if (u == v) continue

                val cost_1 = Math.abs(nums[u] - nums[v])
                val new_dist_1 = dist[u] + cost_1

                if (new_dist_1 < dist[v]) {
                    dist[v] = new_dist_1
                    pq.add(Pair(new_dist_1, v))
                }
            }
        }

        if (!targetReached) {
            // Should not happen given the graph connectivity
            results.add(-1L) 
        }
    }

    return results.toTypedArray()
}
